// Extrai dados da mensagem recebida pela Evolution API
const body = $input.first().json.body || $input.first().json;

// Suporte a diferentes formatos da Evolution API v2
const data = body.data || body;
const message = data.message || {};
const key = data.key || {};

// Número do remetente (remove @s.whatsapp.net)
const rawNumber = key.remoteJid || '';
const fromNumber = rawNumber.replace('@s.whatsapp.net', '').replace('@c.us', '');
const messageId = key.id || data.id || body.id || '';

// Ignora mensagens de grupos
if (rawNumber.includes('@g.us')) {
  return [{ json: { ignore: true } }];
}

// Ignora mensagens enviadas pelo próprio bot
if (key.fromMe) {
  return [{ json: { ignore: true } }];
}

// Tipo de mensagem
const messageType = data.messageType || 'conversation';
let textContent = '';
let hasImage = false;
let imageBase64 = '';
let imageCaption = '';

if (messageType === 'conversation' || messageType === 'extendedTextMessage') {
  textContent = message.conversation || message.extendedTextMessage?.text || '';
} else if (messageType === 'imageMessage') {
  hasImage = true;
  imageCaption = message.imageMessage?.caption || '';
  // base64 da imagem pode vir em base64 ou jpegThumbnail
  imageBase64 = data.message?.base64 || message.imageMessage?.jpegThumbnail || '';
  textContent = imageCaption;
} else if (messageType === 'audioMessage') {
  textContent = '[AUDIO - não suportado ainda]';
}

const pushName = data.pushName || 'Usuário';

return [{
  json: {
    fromNumber,
    messageId,
    pushName,
    textContent: textContent.trim(),
    hasImage,
    imageBase64,
    messageType,
    ignore: false,
    rawBody: body
  }
}];

const response = $input.first().json;
const statusCode = response.statusCode || 200;
const body = response.body || response;

// Verifica se usuário existe e tem plano ativo
const usuario = typeof body === 'string' ? JSON.parse(body) : body;

const encontrado = !!(usuario && usuario.id);
const planoAtivo = encontrado && (usuario.plano_ativo === true || usuario.plano_status === 'ativo' || usuario.plano_status === 'ativa' || usuario.plano_status === 'trialing');
const planoExpirado = encontrado && usuario.plano_status === 'expirado';

// Passa dados do contexto anterior
const ctx = $('Extrair Dados da Mensagem').first().json;

return [{
  json: {
    ...ctx,
    usuario_encontrado: encontrado,
    plano_ativo: planoAtivo,
    plano_expirado: planoExpirado,
    usuario_id: usuario?.id || null,
    usuario_nome: usuario?.nome || ctx.pushName,
    usuario_sessao: usuario?.sessao_php || null,
    plano_nome: usuario?.plano_nome || null,
    conta_id_padrao: usuario?.conta_id_padrao || 1
  }
}];

const ctx = $input.first().json;
let mensagem = '';

if (!ctx.usuario_encontrado) {
  mensagem = `Olá! 👋 Não encontrei uma conta vinculada a este número.\n\nPara usar o *Fina* pelo WhatsApp, acesse o painel e vincule seu número nas configurações:\n👉 https://financias.stackcode.com.br/paginas/perfil.php`;
} else if (ctx.plano_expirado) {
  mensagem = `Olá, ${ctx.usuario_nome}! 😕\n\nSeu plano *expirou*. Para continuar gerenciando suas finanças pelo WhatsApp, renove sua assinatura:\n👉 https://financias.stackcode.com.br/paginas/assinatura.php`;
} else {
  mensagem = `Olá, ${ctx.usuario_nome}! 😕\n\nSua conta está *inativa*. Acesse o painel para verificar:\n👉 https://financias.stackcode.com.br`;
}

return [{ json: { ...ctx, mensagem_resposta: mensagem } }];

const ctx = $('Usuário Válido e Ativo?').first().json;
const resp = $input.first().json;

const texto = (ctx.textContent || '').trim();
const contexto = resp.contexto || null;
const temContexto = !!resp.tem_contexto && !!contexto;

const parseValor = (input) => {
  if (!input) return null;
  const cleaned = String(input).replace(/R\$/gi, '').replace(/\s+/g, '').replace(/\./g, '').replace(',', '.');
  const n = parseFloat(cleaned);
  return Number.isFinite(n) && n > 0 ? n : null;
};

let usarContexto = false;
let transacao_payload = null;
let gpt_resultado = ctx.gpt_resultado || null;

if (temContexto && contexto.payload_parcial?.aguardando_campo === 'valor') {
  const valor = parseValor(texto);
  if (valor) {
    usarContexto = true;
    transacao_payload = {
      tipo: contexto.payload_parcial.tipo || 'despesa',
      descricao: contexto.payload_parcial.descricao || 'Despesa',
      valor,
      data_transacao: contexto.payload_parcial.data_transacao || new Date().toISOString().split('T')[0],
      categoria_id: contexto.payload_parcial.categoria_id || 1,
      conta_id: contexto.payload_parcial.conta_id || ctx.conta_id_padrao || 1,
      origem_message_id: ctx.messageId || null
    };
    gpt_resultado = {
      tipo: transacao_payload.tipo,
      descricao: transacao_payload.descricao,
      valor,
      data_transacao: transacao_payload.data_transacao,
      categoria_sugerida: contexto.payload_parcial.categoria_sugerida || 'Outros'
    };
  }
}

return [{ json: { ...ctx, contexto_pendente: contexto, tem_contexto_pendente: temContexto, usar_contexto: usarContexto, transacao_payload, gpt_resultado } }];

// Detecta a intenção do usuário pela mensagem
const ctx = $input.first().json;
const texto = (ctx.textContent || '').toLowerCase().trim();

let intencao = 'registrar_transacao'; // padrão

// Consultas
if (/^saldo$|^meu saldo|^ver saldo|^qual.*saldo/.test(texto)) {
  intencao = 'consultar_saldo';
} else if (/^extrato|^transações|^transacoes|^historico|^histórico|^gastos do mes|^gastos deste mes/.test(texto)) {
  // No fluxo atual, extrato é respondido pelo resumo do mês para evitar fallback silencioso.
  intencao = 'consultar_totais';
} else if (/^resumo|^totais|^quanto.*gastei.*mes|^balanço|^balanco/.test(texto)) {
  intencao = 'consultar_totais';
} else if (/^ajuda|^help|^comandos|^o que.*fazer/.test(texto)) {
  intencao = 'ajuda';
} else if (ctx.hasImage) {
  intencao = 'registrar_transacao_imagem';
}

return [{ json: { ...ctx, intencao } }];

const ctx = $('Detectar Intenção').first().json;
const resp = $input.first().json;
const saldo = resp.saldo ?? 0;
const formatado = new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(saldo);

const mensagem = `💰 *Seu saldo atual é: ${formatado}*\n\nPara ver o resumo do mês, envie *resumo*.`;

return [{ json: { ...ctx, mensagem_resposta: mensagem } }];

const ctx = $('Detectar Intenção').first().json;
const resp = $input.first().json;

const fmt = (v) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v ?? 0);
const mes = new Date().toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

const receitas = resp.receitas ?? 0;
const despesas = resp.despesas ?? 0;
const saldo = resp.saldo ?? (receitas - despesas);

const mensagem = `📊 *Resumo de ${mes}*\n\n✅ Receitas: ${fmt(receitas)}\n❌ Despesas: ${fmt(despesas)}\n━━━━━━━━━━━━\n💰 Saldo: ${fmt(saldo)}\n\nPara registrar um gasto, envie algo como:\n_"Gastei 45 reais com almoço"_`;

return [{ json: { ...ctx, mensagem_resposta: mensagem } }];

const ctx = $input.first().json;
const mensagem = `👋 Olá, *${ctx.usuario_nome}*! Aqui estão os comandos disponíveis:

💬 *Registrar transação:*
_"Gastei 50 no mercado"_
_"Recebi 3000 de salário"_
_"Paguei 120 de conta de luz"_

📷 *Enviar comprovante:*
Mande uma foto e eu identifico automaticamente

📊 *Consultas:*
• *saldo* — ver saldo atual
• *resumo* — totais do mês

Simples assim! 🚀`;

return [{ json: { ...ctx, mensagem_resposta: mensagem } }];

// Prepara o prompt para o GPT processar a mensagem
const ctx = $input.first().json;

const hoje = new Date().toISOString().split('T')[0];

const systemPrompt = `Você é um assistente de finanças pessoais integrado ao sistema Fina via WhatsApp.
Sua função é extrair informações financeiras de mensagens do usuário e retornar um JSON estruturado.

Retorne APENAS JSON válido.
Formato de saída:
{
  "status": "TRANSACAO_COMPLETA" | "TRANSACAO_INCOMPLETA" | "NAO_ENTENDIDO",
  "tipo": "receita" | "despesa" | null,
  "valor": number | null,
  "descricao": string | null,
  "data_transacao": "YYYY-MM-DD" | null,
  "categoria_sugerida": string | null,
  "campos_faltantes": string[],
  "pergunta_sugerida": string,
  "confianca": number
}

Regras:
- Se faltarem dados, use status TRANSACAO_INCOMPLETA.
- Para frase tipo "assinei netflix" classifique como despesa com descricao "Assinatura Netflix" e valor null.
- Se só faltar valor, campos_faltantes deve conter apenas ["valor"] e pergunta_sugerida deve perguntar o valor.
- valor deve ser número decimal positivo quando existir.
- data_transacao: se não mencionado, use ${hoje}.
- categoria_sugerida em português.
- Se não for mensagem financeira, use status NAO_ENTENDIDO.
`;

const userMessage = ctx.hasImage
  ? `O usuário enviou uma imagem de comprovante com a legenda: "${ctx.textContent || 'sem legenda'}". Extraia os dados da transação.`
  : ctx.textContent;

return [{
  json: {
    ...ctx,
    gpt_system: systemPrompt,
    gpt_user: userMessage
  }
}];

const ctx = $('Preparar Prompt GPT').first().json;
const gptResp = $input.first().json;

let parsed = null;
let erro = null;

const toNumber = (v) => {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  const raw = String(v).replace(/R\$/gi, '').replace(/\s+/g, '').replace(/\./g, '').replace(',', '.');
  const n = parseFloat(raw);
  return Number.isFinite(n) ? n : null;
};

try {
  const content = gptResp.choices?.[0]?.message?.content || '{}';
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  erro = 'PARSE_ERROR';
}

if (parsed?.erro) {
  erro = parsed.erro;
}

if (parsed) {
  parsed.valor = toNumber(parsed.valor);
  parsed.status = parsed.status || (parsed.tipo && parsed.descricao && parsed.valor ? 'TRANSACAO_COMPLETA' : 'TRANSACAO_INCOMPLETA');
  parsed.campos_faltantes = Array.isArray(parsed.campos_faltantes) ? parsed.campos_faltantes : [];

  if (!parsed.data_transacao) {
    parsed.data_transacao = new Date().toISOString().split('T')[0];
  }

  if (parsed.status === 'TRANSACAO_INCOMPLETA' && parsed.campos_faltantes.length === 0) {
    if (!parsed.valor) parsed.campos_faltantes.push('valor');
    if (!parsed.tipo) parsed.campos_faltantes.push('tipo');
    if (!parsed.descricao) parsed.campos_faltantes.push('descricao');
  }
}

if (parsed?.status === 'NAO_ENTENDIDO') {
  erro = 'NAO_ENTENDIDO';
}

if (parsed?.status === 'TRANSACAO_INCOMPLETA' && parsed?.campos_faltantes?.includes('valor')) {
  erro = 'FALTANDO_VALOR';
}

const valido = !erro && parsed && parsed.status === 'TRANSACAO_COMPLETA' && parsed.tipo && parsed.valor && parsed.descricao;

return [{
  json: {
    ...ctx,
    gpt_resultado: parsed,
    gpt_valido: valido,
    gpt_erro: erro
  }
}];

const ctx = $('Processar Resposta GPT').first().json;
const catResp = $input.first().json;

let categoriaId = null;
let categoriaNome = ctx.gpt_resultado?.categoria_sugerida || 'Outros';

if (catResp.categorias && catResp.categorias.length > 0) {
  categoriaId = catResp.categorias[0].id;
  categoriaNome = catResp.categorias[0].nome;
}

return [{
  json: {
    ...ctx,
    categoria_id: categoriaId,
    categoria_nome: categoriaNome
  }
}];

// Determina o categoria_id final (existente ou recém criada)
const ctx = $('Resolver Categoria').first().json;
let categoriaId = ctx.categoria_id;

// Se veio do branch de criação
try {
  const criada = $('API: Criar Categoria').first().json;
  if (criada.sucesso && criada.id) {
    categoriaId = criada.id;
  }
} catch(e) { /* branch de categoria existente */ }

const transacao = {
  tipo: ctx.gpt_resultado.tipo,
  descricao: ctx.gpt_resultado.descricao,
  valor: ctx.gpt_resultado.valor,
  data_transacao: ctx.gpt_resultado.data_transacao || new Date().toISOString().split('T')[0],
  categoria_id: categoriaId,
  conta_id: ctx.conta_id_padrao || 1,
  origem_message_id: ctx.messageId || null
};

return [{ json: { ...ctx, transacao_payload: transacao } }];

const ctx = $input.first().json;
const resp = $input.first().json;

const fmt = (v) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(v);

if (!resp.sucesso) {
  return [{ json: { ...ctx, mensagem_resposta: `❌ Erro ao salvar a transação. Tente novamente ou acesse o painel.`, salvo: false } }];
}

const t = ctx.transacao_payload;
const emoji = t.tipo === 'receita' ? '✅' : '❌';
const tipoLabel = t.tipo === 'receita' ? 'Receita' : 'Despesa';

const data = new Date(t.data_transacao + 'T12:00:00').toLocaleDateString('pt-BR');
const categoria = ctx.categoria_nome || ctx.gpt_resultado?.categoria_sugerida || 'Outros';
const duplicada = resp.resultado?.origem_message_id && resp.resultado?.id && resp.resultado.origem_message_id === t.origem_message_id;

const mensagem = `${emoji} *${tipoLabel} registrada!*\n\n📝 ${t.descricao}\n💰 ${fmt(t.valor)}\n🏷️ ${categoria}\n📅 ${data}${duplicada ? '\n\nℹ️ Mensagem duplicada detectada, mantive apenas um registro.' : ''}\n\nPara ver seu saldo, envie *saldo*.`;

return [{ json: { ...ctx, mensagem_resposta: mensagem, salvo: true } }];

const ctx = $input.first().json;
const erro = ctx.gpt_erro;
const texto = (ctx.textContent || '').trim();

let mensagem = '';
if (erro === 'FALTANDO_VALOR') {
  const desc = ctx.gpt_resultado?.descricao || 'essa transação';
  mensagem = `Perfeito, entendi: *${desc}*.\n\nQual foi o valor? (ex: 39,90)`;
} else if (erro === 'NAO_ENTENDIDO') {
  if (texto.length <= 3) {
    mensagem = `Consegue me mandar com mais detalhes?\n\nExemplos:\n• _"Gastei 50 no mercado"_\n• _"Recebi 1500 de freelance"_`;
  } else {
    mensagem = `Não consegui identificar uma transação nessa frase.\n\nTente algo como:\n• _"Gastei 50 reais no mercado"_\n• _"Recebi 1500 de freelance"_\n• _"Paguei 80 de gasolina"_\n\nSe preferir, envie *ajuda*.`;
  }
} else {
  mensagem = `⚠️ Houve um problema ao processar sua mensagem. Tente novamente em instantes.`;
}

return [{ json: { ...ctx, mensagem_resposta: mensagem } }];

// Merge de todas as saídas para envio via Evolution API
// Pega o dado de qualquer nó anterior que tenha mensagem_resposta
const items = $input.all();
const item = items.find(i => i.json.mensagem_resposta) || items[0];

return [{ json: item.json }];
